import React, { useState } from 'react';
import './SideNav.css';  // Import the styles for the side navigation

function SideNav() {
  const [isOpen, setIsOpen] = useState(false); // State to control the open/close of the side nav

  const toggleNav = () => {
    setIsOpen(!isOpen); // Toggle the side navigation visibility
  };

  return (
    <div className="side-nav-container">
      <div
        className={`side-nav ${isOpen ? 'open' : ''}`} // Apply 'open' class when side nav is open
      >
        <ul>
          <li><a href="/Main">Home</a></li>
          <li><a href="/Profile">Profile</a></li>
          <li><a href="/Settings">Settings</a></li>
          <li><a href="/Logout">Logout</a></li>
        </ul>
      </div>

      <div className={`arrow ${isOpen ? 'rotate' : ''}`} onClick={toggleNav}>
        &#8594; {/* Arrow character */}
      </div>
    </div>
  );
}

export default SideNav;
